import "./index.css";
import React from "react";
import ReactDOM from "react-dom/client";
import { App } from "./App";

const rootEl = document.getElementById("root");
if (rootEl) {
  ReactDOM.createRoot(rootEl).render(<App />);
}

/* @import url() FONT IMPORTS MUST ALWAYS BE AT THE VERY TOP OF THIS FILE, ABOVE THE TAILWIND IMPORTS — DO NOT DELETE THIS COMMENT */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

/* CRITICAL: THE FOLLOWING TAILWIND IMPORTS MUST NEVER BE DELETED OR REORDERED — DO NOT DELETE THIS COMMENT */
@import 'tailwindcss/base';
@import 'tailwindcss/components';
@import 'tailwindcss/utilities';

/* END TAILWIND IMPORTS — ALL OTHER CSS MUST GO BELOW THIS LINE */

body {
  background-color: #050505;
  color: #ffffff;
  font-family: 'Inter', sans-serif;
  -webkit-font-smoothing: antialiased;
}
::selection {
  background-color: rgba(16, 185, 129, 0.3);
  color: white;
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
      },
      colors: {
        background: '#050505',
        surface: '#0a0a0a',
        surfaceHover: '#141414',
        border: '#1f1f1f',
        primary: '#10b981', // emerald-500
        primaryHover: '#059669', // emerald-600
        secondary: '#06b6d4', // cyan-500
      },
      backgroundImage: {
        'gradient-radial': 'radial-gradient(var(--tw-gradient-stops))',
        'hero-glow': 'conic-gradient(from 180deg at 50% 50%, #10b98133 0deg, #06b6d433 180deg, #10b98133 360deg)',
      }
    },
  },
  plugins: [],
}

export const manifest = {
  screens: {
    scr_xdgy7r: { name: "Home", route: "/" },
  },
}

import { useMemo } from 'react'
import { manifest } from './canvas.manifest.js'

export function useScreenInit() {
  return useMemo(() => {
    if (typeof window === 'undefined') return {}
    const screenId = new URLSearchParams(window.location.search).get('mp_screen')
    if (!screenId) return {}
    return manifest?.screens?.[screenId]?.state ?? {}
  }, [])
}

import React from 'react'
import { motion } from 'framer-motion'
import { Download, Key, MessageCircle } from 'lucide-react'
const steps = [
  {
    icon: Download,
    title: '1. Download the Kit',
    description:
      "Purchase the $50 starter kit. You'll get a lightweight installer for Mac or Windows that sets up the local environment automatically.",
  },
  {
    icon: Key,
    title: '2. Authenticate',
    description:
      'Sign in with your existing ChatGPT Plus account and Google Workspace using secure OAuth. No API keys to manage.',
  },
  {
    icon: MessageCircle,
    title: '3. Chat on Telegram',
    description:
      'Enter your one-time purchase code to allowlist your Telegram handle. Start messaging Roz immediately.',
  },
]
export function HowItWorks() {
  return (
    <section
      id="how-it-works"
      className="py-24 bg-surface/30 border-y border-border relative"
    >
      <div className="max-w-7xl mx-auto px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">
            From zero to assistant in 3 steps
          </h2>
          <p className="text-gray-400 max-w-2xl mx-auto">
            We've abstracted away the complex setup of open-source agents. If
            you can install a normal app, you can run Roz.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 relative">
          {/* Connecting line for desktop */}
          <div className="hidden md:block absolute top-12 left-[15%] right-[15%] h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />

          {steps.map((step, index) => (
            <motion.div
              key={index}
              initial={{
                opacity: 0,
                y: 20,
              }}
              whileInView={{
                opacity: 1,
                y: 0,
              }}
              viewport={{
                once: true,
              }}
              transition={{
                duration: 0.5,
                delay: index * 0.2,
              }}
              className="relative bg-surface border border-white/5 rounded-2xl p-8 hover:bg-surfaceHover transition-colors"
            >
              <div className="w-16 h-16 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center mb-6 relative z-10">
                <step.icon className="w-8 h-8 text-primary" />
              </div>
              <h3 className="text-xl font-semibold text-white mb-3">
                {step.title}
              </h3>
              <p className="text-gray-400 leading-relaxed">
                {step.description}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  )
}

import React from 'react'
import { motion } from 'framer-motion'
import { Mail, Calendar, FileText, Cpu, Blocks } from 'lucide-react'
